<script setup lang="ts">
import { Head, Link, router } from '@inertiajs/vue3';import { AlertTriangle, CheckCircle2, Clock3, Laptop, LockKeyhole, LogOut, MapPin, MonitorSmartphone, RefreshCw, ShieldCheck, Smartphone, Tablet } from '@lucide/vue';import { computed, onMounted, ref } from 'vue';import AppShell from '../../Layouts/AppShell.vue';
const sessions=ref<any[]>([]),recentLogins=ref<any[]>([]),loading=ref(true),busy=ref(''),notice=ref(''),error=ref('');const csrf=()=>(document.querySelector('meta[name="csrf-token"]') as HTMLMetaElement)?.content??'';const current=computed(()=>sessions.value.find(x=>x.current));const others=computed(()=>sessions.value.filter(x=>!x.current));const icon=(type:string)=>type==='mobile'?Smartphone:type==='tablet'?Tablet:Laptop;
async function api(url:string,method='GET'){const r=await fetch(url,{method,credentials:'same-origin',headers:{Accept:'application/json','X-CSRF-TOKEN':csrf()}});const p=await r.json();if(!r.ok)throw new Error(p.message??'Unable to update sessions.');return p}async function load(){loading.value=true;error.value='';try{const payload=await api('/api/v1/auth/sessions');sessions.value=payload.data;recentLogins.value=payload.recent_logins??[]}catch(e:any){error.value=e.message}finally{loading.value=false}}
async function revoke(session:any){if(!confirm(`Sign out ${session.browser} on ${session.platform}?`))return;busy.value=session.id;try{const p=await api('/api/v1/auth/sessions/'+encodeURIComponent(session.id),'DELETE');notice.value=p.message;sessions.value=sessions.value.filter(x=>x.id!==session.id)}catch(e:any){error.value=e.message}finally{busy.value=''}}async function revokeOthers(){if(!others.value.length||!confirm('Sign out every other device? Your current device will remain signed in.'))return;busy.value='others';try{const p=await api('/api/v1/auth/sessions/others','DELETE');notice.value=p.message;sessions.value=sessions.value.filter(x=>x.current)}catch(e:any){error.value=e.message}finally{busy.value=''}}const logout=()=>router.post('/logout');const when=(value:string)=>new Intl.RelativeTimeFormat('en',{numeric:'auto'}).format(-Math.max(0,Math.round((Date.now()-new Date(value).getTime())/60000)),'minute');const loginDate=(value:string)=>new Intl.DateTimeFormat('en-ZA',{dateStyle:'medium',timeStyle:'short'}).format(new Date(value));
onMounted(load);
</script>
<template><Head title="Sessions & Devices"/><AppShell><main class="devices-page"><header><div><span><ShieldCheck/> ACCOUNT SECURITY</span><h1>Sessions & devices</h1><p>Review where your account is signed in and remove access you do not recognise.</p></div><button :disabled="loading" @click="load"><RefreshCw/>Refresh</button></header><p v-if="notice" class="session-alert success"><CheckCircle2/>{{ notice }}</p><p v-if="error" class="session-alert error"><AlertTriangle/>{{ error }}</p><div class="security-summary"><article><MonitorSmartphone/><div><strong>{{ sessions.length }}</strong><span>Active sessions</span></div></article><article><ShieldCheck/><div><strong>{{ others.length?'Review':'Protected' }}</strong><span>{{ others.length }} other devices</span></div></article><article><Clock3/><div><strong>{{ current?.active_now?'Now':'Recent' }}</strong><span>Current activity</span></div></article></div><section v-if="loading" class="device-panel loading">Loading signed-in devices…</section><template v-else><section v-if="current" class="device-panel"><div class="panel-heading"><div><small>THIS DEVICE</small><h2>Your current session</h2></div><b>Active now</b></div><article class="device-row current"><span class="device-icon"><component :is="icon(current.type)"/></span><div class="device-copy"><strong>{{ current.browser }} on {{ current.platform }}</strong><p><MapPin/>IP {{ current.ip_address||'Unavailable' }}</p><small>Current device · Last active {{ when(current.last_active_at) }}</small></div><button class="signout-current" @click="logout"><LogOut/>Sign out</button></article></section><section class="device-panel"><div class="panel-heading"><div><small>OTHER SESSIONS</small><h2>Other signed-in devices</h2></div><button v-if="others.length" class="signout-all" :disabled="busy==='others'" @click="revokeOthers"><LockKeyhole/>{{ busy==='others'?'Signing out…':'Sign out all others' }}</button></div><div v-if="others.length"><article v-for="session in others" :key="session.id" class="device-row"><span class="device-icon"><component :is="icon(session.type)"/></span><div class="device-copy"><strong>{{ session.browser }} on {{ session.platform }}</strong><p><MapPin/>IP {{ session.ip_address||'Unavailable' }}</p><small>{{ session.active_now?'Active recently':`Last active ${when(session.last_active_at)}` }}</small></div><button :disabled="busy===session.id" @click="revoke(session)"><LogOut/>{{ busy===session.id?'Signing out…':'Sign out' }}</button></article></div><div v-else class="no-devices"><ShieldCheck/><h3>No other active sessions</h3><p>Your account is currently signed in only on this device.</p></div></section><section class="device-panel"><div class="panel-heading"><div><small>LOGIN HISTORY</small><h2>Five most recent logins</h2></div></div><div v-if="recentLogins.length"><article v-for="login in recentLogins" :key="login.id" class="device-row login-history-row"><span class="device-icon"><component :is="icon(login.type)"/></span><div class="device-copy"><strong>{{ login.browser }} on {{ login.platform }}</strong><p><MapPin/>{{ login.location }} · IP {{ login.ip_address||'Unavailable' }}</p><small>{{ loginDate(login.logged_in_at) }} · {{ login.method==='password'?'Password':login.method }}</small></div></article></div><div v-else class="no-devices"><Clock3/><h3>No previous login history yet</h3><p>Your next successful sign-ins will appear here.</p></div></section><section class="security-tip"><LockKeyhole/><div><strong>Do you see a device you do not recognise?</strong><p>Sign it out immediately, then change your password from Profile settings. This invalidates access from that session.</p><Link href="/profile/edit">Review profile security</Link></div></section></template></main></AppShell></template>
<style scoped>.devices-page{width:100%;max-width:1240px;margin:auto;padding:32px 32px 80px}.devices-page>header{display:flex;justify-content:space-between;align-items:flex-end}.devices-page header span{display:flex;gap:6px;color:#1769ed;font-weight:800}.devices-page h1{font-size:clamp(30px,5vw,48px);margin:6px 0}.devices-page header p{color:#718096}.devices-page header>button{display:flex;gap:7px;align-items:center;padding:10px 14px;border:1px solid #d9e2ec;border-radius:10px;background:white}.security-summary{display:grid;grid-template-columns:repeat(3,1fr);gap:14px;margin:22px 0}.security-summary article,.device-panel,.security-tip{border:1px solid #dce4ed;border-radius:17px;background:white}.security-summary article{display:flex;gap:14px;align-items:center;padding:18px}.security-summary svg{color:#1769ed}.security-summary strong,.security-summary span{display:block}.security-summary strong{font-size:22px}.security-summary span{color:#718096}.device-panel{padding:22px;margin-bottom:16px}.panel-heading{display:flex;justify-content:space-between;align-items:center}.panel-heading small{color:#1769ed;font-weight:800}.panel-heading h2{margin:4px 0}.panel-heading>b{padding:6px 9px;color:#12805c;border-radius:999px;background:#e5f8f0}.device-row{display:flex;gap:15px;align-items:center;padding:18px 0;border-top:1px solid #e8edf2}.device-icon{display:grid;width:52px;height:52px;flex:none;place-items:center;color:#1769ed;border-radius:14px;background:#edf4ff}.device-copy{flex:1}.device-copy p,.device-copy small{display:flex;gap:5px;align-items:center;color:#718096}.device-copy p{margin:5px 0}.device-copy svg{width:13px}.device-row>button,.signout-all{display:flex;gap:6px;align-items:center;padding:9px 12px;color:#b4233f;border:1px solid #f0c9d1;border-radius:9px;background:#fff7f8}.device-row>button svg,.signout-all svg{width:15px}.current{border-top:0}.current .signout-current{color:#536274;border-color:#d9e2ec;background:white}.login-history-row:first-child{border-top:0}.no-devices{padding:35px;text-align:center;color:#718096}.no-devices svg{color:#169568}.security-tip{display:flex;gap:15px;padding:20px;background:#f5f8fc}.security-tip svg{color:#1769ed}.security-tip p{color:#657388}.security-tip a{color:#1769ed}.session-alert{display:flex;gap:8px;padding:12px;border-radius:10px}.session-alert.success{color:#166534;background:#dcfce7}.session-alert.error{color:#991b1b;background:#fee2e2}.loading{text-align:center;color:#718096}@media(max-width:700px){.devices-page{padding:18px 14px 96px}.devices-page>header{align-items:flex-start;flex-direction:column;gap:10px}.security-summary{grid-template-columns:1fr}.panel-heading{align-items:flex-start;gap:10px;flex-direction:column}.device-row{align-items:flex-start;flex-wrap:wrap}.device-copy{min-width:calc(100% - 70px)}.device-row>button{margin-left:67px}.security-tip{align-items:flex-start}}</style>
